import{_ as t,o,c as s,a2 as a}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"RFC 0010 — Test file organization","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0010-test-organization.md","filePath":"rfcs/0010-test-organization.md"}'),n={name:"rfcs/0010-test-organization.md"};function i(r,e,d,c,l,h){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-0010-—-test-file-organization" tabindex="-1">RFC 0010 — Test file organization <a class="header-anchor" href="#rfc-0010-—-test-file-organization" aria-label="Permalink to &quot;RFC 0010 — Test file organization&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>vitest.config.ts</code>, all <code>*.test.ts(x)</code> locations, a new root <code>/__tests__/</code>, <code>package.json</code> test scripts, CLAUDE.md + CONTRIBUTING test conventions<br><strong>Incorporated into plan:</strong> Yes — <strong>Task 0.5.17</strong> (decision-log row in SRS §6). The file moves + Vitest glob/script changes + CLAUDE.md/CONTRIBUTING updates land in that task.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Adopt an <strong>intentional, boundary-aware test layout</strong> as the suite grows to span unit, integration, e2e (future), and visual (future) tiers. The organizing principle is: <strong>a test&#39;s placement follows the boundary it crosses, not its &quot;type&quot; label.</strong></p><ul><li>Tests that belong to <strong>one workspace package</strong> live <strong>inside that package</strong> in per-directory <code>__tests__/</code> folders.</li><li>Tests that belong to <strong>no single package</strong> — cross-service integration and e2e — live at the <strong>root <code>/__tests__/</code></strong>.</li></ul><table tabindex="0"><thead><tr><th>Test kind</th><th>Location</th><th>Naming</th></tr></thead><tbody><tr><td>Unit, component, <strong>visual</strong> (future)</td><td>per-dir <code>__tests__/</code> inside the owning package</td><td><code>*.test.ts(x)</code>, <code>*.visual.test.tsx</code></td></tr><tr><td><strong>Within-package</strong> integration</td><td>the owning package&#39;s <code>__tests__/</code></td><td><code>*.integration.test.ts</code></td></tr><tr><td><strong>Cross-service</strong> integration</td><td>root <code>/__tests__/integration/</code></td><td><code>*.integration.test.ts</code></td></tr><tr><td><strong>E2e</strong> (Playwright, future)</td><td>root <code>/__tests__/e2e/</code></td><td><code>*.e2e.ts</code> / <code>*.spec.ts</code></td></tr><tr><td>Postgres parity (existing, env-gated)</td><td>stays in its package</td><td><code>*.pg.test.ts</code> (unchanged)</td></tr><tr><td>docs-parity / schema-parity</td><td>stay in <code>runtime</code> / <code>packages/db</code> <code>__tests__/</code></td><td>unchanged</td></tr></tbody></table><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Today all 31 test files are <strong>flat-co-located</strong> (<code>*.test.ts(x)</code> directly beside source) under a single root <code>vitest.config.ts</code>. That is fine for a unit-only suite, but as e2e and visual tiers arrive the flat layout gives no signal of a test&#39;s <em>kind</em> or <em>scope</em>, and offers no obvious home for tests that span the runtime ↔ auth boundary or drive a browser. This RFC introduces structure <strong>before</strong> those tiers land, so the conventions exist when the first e2e/visual test is written — without disturbing the lean current suite.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Single root config</strong> — <code>vitest.config.ts</code> with workspace-wide <code>include</code> globs (<code>packages/**/src</code>, <code>apps/**/src</code>, <code>runtime/src</code>, <code>plugins/**</code>, <code>scripts/**</code>, <code>bin/**</code>); <code>environment: &#39;node&#39;</code> by default with components opting into jsdom via a <code>// @vitest-environment jsdom</code> pragma; <code>classNameStrategy: &#39;non-scoped&#39;</code> for CSS-module assertions.</li><li><strong>31 test files, 100% flat-co-located</strong>, clustered in <code>packages/*</code>, <code>runtime/src</code>, <code>apps/auth/src</code>, <code>bin</code>, <code>scripts</code>, <code>plugins/*</code>.</li><li><strong>Env-gated Postgres parity</strong> tests (<code>*.pg.test.ts</code>) — skipped unless <code>TEST_DATABASE_URL</code> is set (CONTRIBUTING documents this).</li><li><strong>Special validators:</strong> <code>runtime/src/docs-parity.test.ts</code>, <code>packages/db/src/schema/parity.test.ts</code>.</li><li><strong>No e2e / visual tooling yet</strong> — no Playwright/Cypress/Storybook; <code>@testing-library/react</code> is used for jsdom component tests only.</li><li><strong><code>pnpm test</code> runs Vitest from root</strong> (<code>vitest run</code>); turbo has no <code>test</code> task.</li><li>CLAUDE.md documents the current convention as &quot;co-located <code>*.test.ts</code>&quot;.</li></ul><h2 id="proposed-design-the-layout-is-deferred-this-rfc-settles-the-convention" tabindex="-1">Proposed design (the layout is deferred; this RFC settles the convention) <a class="header-anchor" href="#proposed-design-the-layout-is-deferred-this-rfc-settles-the-convention" aria-label="Permalink to &quot;Proposed design (the layout is deferred; this RFC settles the convention)&quot;">​</a></h2><h3 id="the-boundary-rule" tabindex="-1">The boundary rule <a class="header-anchor" href="#the-boundary-rule" aria-label="Permalink to &quot;The boundary rule&quot;">​</a></h3><p>In a pnpm + Turborepo monorepo, a test belongs to the <strong>package that owns the code under test</strong>, so it stays near its subject and can run/cache per package. The root <code>/__tests__/</code> is reserved for tests that belong to <strong>no</strong> single package — full-stack flows that wire runtime and auth together, and browser e2e. This is why &quot;integration&quot; is <strong>not</strong> one location: a test that integrates two modules <strong>within</strong> <code>packages/db</code> is a package-local test; a test that exercises runtime → auth over HTTP is a root test. Placement tracks the widest boundary the test crosses.</p><h3 id="within-a-package" tabindex="-1">Within a package <a class="header-anchor" href="#within-a-package" aria-label="Permalink to &quot;Within a package&quot;">​</a></h3><p>Unit, component, and (future) visual tests move from flat co-location into per-directory <code>__tests__/</code> folders beside the code they cover, e.g. <code>packages/ui/src/components/__tests__/Button.test.tsx</code>. Within-package integration tests live in the same <code>__tests__/</code> folders, distinguished by the <code>*.integration.test.ts</code> suffix. The existing special validators (<code>docs-parity</code>, <code>schema-parity</code>) and the env-gated <code>*.pg.test.ts</code> parity tests are package-local and <strong>stay in their packages</strong> (moved into <code>__tests__/</code>, names unchanged).</p><h3 id="at-the-root" tabindex="-1">At the root <a class="header-anchor" href="#at-the-root" aria-label="Permalink to &quot;At the root&quot;">​</a></h3><p><code>/__tests__/integration/</code> for cross-service integration and <code>/__tests__/e2e/</code> for browser e2e (with <code>/__tests__/visual/</code> reserved for visual regression). These are created empty (with a short README) now; they fill as those tiers are built.</p><h3 id="naming-disambiguation" tabindex="-1">Naming &amp; disambiguation <a class="header-anchor" href="#naming-disambiguation" aria-label="Permalink to &quot;Naming &amp; disambiguation&quot;">​</a></h3><p>Filename suffixes let a tier be targeted independently of location: <code>*.test.ts(x)</code> (unit/component), <code>*.integration.test.ts</code>, <code>*.visual.test.tsx</code>, <code>*.e2e.ts</code> (or Playwright <code>*.spec.ts</code>), and the existing <code>*.pg.test.ts</code>. Companion scripts — <code>test</code> (all), <code>test:unit</code>, <code>test:integration</code>, <code>test:e2e</code> — select tiers. Optionally adopt <strong>Vitest &quot;projects&quot;</strong> to give node, jsdom, and e2e their own environments/config; whether to do that now or stay glob-only is an open question.</p><h3 id="tooling-reservations-future-—-no-dependencies-added-now" tabindex="-1">Tooling reservations (future — no dependencies added now) <a class="header-anchor" href="#tooling-reservations-future-—-no-dependencies-added-now" aria-label="Permalink to &quot;Tooling reservations (future — no dependencies added now)&quot;">​</a></h3><p>E2e is expected to be <strong>Playwright</strong>; visual regression either Playwright screenshots or Storybook/Chromatic. This RFC only reserves the <code>/__tests__/{e2e, visual}</code> locations and the naming; the tools are chosen and added when those tiers are actually built.</p><h2 id="impact-when-performed-deferred-to-a-later-mechanical-task" tabindex="-1">Impact when performed (deferred to a later mechanical task) <a class="header-anchor" href="#impact-when-performed-deferred-to-a-later-mechanical-task" aria-label="Permalink to &quot;Impact when performed (deferred to a later mechanical task)&quot;">​</a></h2><ul><li>Move the ~31 flat-co-located test files into per-directory <code>__tests__/</code> folders within their packages.</li><li>Update <code>vitest.config.ts</code> <code>include</code> to match <code>**/__tests__/**/*.test.{ts,tsx}</code> inside packages <strong>plus</strong> <code>__tests__/**</code> at the root; keep <code>classNameStrategy</code> and the jsdom pragma working.</li><li>Add the root <code>/__tests__/{integration,e2e}</code> scaffolding (+ a README) and the <code>test:*</code> scripts.</li><li>Update the CLAUDE.md tech-stack/&quot;co-located <code>*.test.ts</code>&quot; line and the CONTRIBUTING testing section to describe the new layout.</li><li><code>*.pg.test.ts</code>, <code>docs-parity</code>, and <code>schema-parity</code> stay within their packages (relocated into <code>__tests__/</code>, behavior unchanged). No turbo <code>test</code> task is required (a per-package task can be added later if caching is wanted).</li></ul><p>This is a single mechanical pass; done in one PR so the suite never sits half-moved.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>All tests by type at the root</strong> (<code>/__tests__/{unit,integration,e2e}</code>). Centralized and simple to picture, but it divorces package-local tests from their code and from per-package run/caching — a regression in a monorepo. Rejected.</li><li><strong>Keep flat side-by-side co-location</strong> (status quo). Zero churn, but gives no signal of test kind/scope and no home for cross-service/e2e tests. Rejected in favour of the <code>__tests__/</code> folder layout.</li><li><strong>Put all &quot;integration&quot; in one place.</strong> Rejected — integration spans a spectrum from two modules in one package to two services over HTTP; one location is wrong for half of them. Hence the boundary rule.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Vitest &quot;projects&quot; now vs glob-only.</strong> Adopt projects to separate node/jsdom/e2e environments immediately, or defer until e2e lands?</li><li><strong>Visual-test suffix.</strong> <code>*.visual.test.tsx</code> vs a Storybook-driven convention.</li><li><strong>Within-package integration form.</strong> Suffix (<code>*.integration.test.ts</code>, proposed) vs a <code>__tests__/integration/</code> subfolder per package.</li><li><strong>E2e tool.</strong> Confirm Playwright when the tier is built.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; boundary-based layout, per-dir <code>__tests__/</code>, root <code>/__tests__/</code>.</td></tr><tr><td>1.0</td><td>Jun 2026</td><td>Accepted; incorporated into the build plan (Task 0.5.17) and a decision-log row.</td></tr><tr><td>1.1</td><td>Jun 2026</td><td>Implemented in Task 0.5.17 (merged to <code>main</code>).</td></tr></tbody></table>',31)])])}const p=t(n,[["render",i]]);export{u as __pageData,p as default};
